class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        n = len(binary)
        first_zero = -1
        count_zeros = 0
        for i in range(n):
            if binary[i] == '0':
                if first_zero == -1:
                    first_zero = i
                count_zeros += 1
        if count_zeros == 0:
            return binary
        return '1' * (first_zero) + '0' + '1' * (n - first_zero - 1)
